CREATE PROCEDURE [dbo].[TR_MATERIAL_OTHER_INSERT]
(
  @id int OUT,
  @mact nvarchar(50) OUT,
  @tenct nvarchar(200),
  @quycach nvarchar(50),
  @mausac nvarchar(50),
  @dvt nvarchar(50), 
  @makho nvarchar(50), 
  @nguoitao nvarchar(50), 
  @ngaytao datetime,
  @nguoisua nvarchar(50),
  @ngaysua datetime, 
  @active bit,
  @hangsanxuat nvarchar(200),
  @dacdiem nvarchar(200),
  @nhomvattu int
)
AS

DECLARE @xacnhan bit = 1
IF(@makho = N'BAO BÌ' or @makho = N'HÓA CHẤT' or @makho = N'NGŨ KIM')
BEGIN
	SET @xacnhan = 0
END

INSERT INTO tr_material_other
(
  tenct,
  quycach,
  mausac,
  dvt, 
  makho, 
  nguoitao, 
  ngaytao,
  nguoisua,
  ngaysua, 
  active,
  hangsanxuat,
  dacdiem,
  nhomvattu
)
VALUES
(
  @tenct,
  @quycach,
  @mausac,
  @dvt, 
  @makho, 
  @nguoitao, 
  @ngaytao,
  @nguoisua,
  @ngaysua, 
  @active,
  @hangsanxuat,
  @dacdiem,
  @nhomvattu
)

SET @id = SCOPE_IDENTITY()
SET @mact = CONCAT(@makho, FORMAT(@id, 'D4'))

DECLARE @tenkho nvarchar(50)
SELECT @tenkho = [description] FROM tr_site WHERE [name] = @makho

DECLARE @tennhom nvarchar(50)
SELECT @tennhom = nhomvattu FROM tr_nhom_vattu WHERE id = @nhomvattu

IF EXISTS (SELECT * FROM tr_material WHERE mavt = @mact)
BEGIN
  UPDATE tr_material
  SET tenvt = @tenct,
      mota = @tenct,
      quycach = @quycach,
      mausac = @mausac,
      dvt = @dvt,
      dacdiem = @dacdiem,
      nhom = @tennhom,
      update_by = @nguoisua,
      update_date = @ngaysua,
	  xacnhan = @xacnhan
  WHERE mavt = @mact
END
ELSE
BEGIN
  INSERT INTO tr_material(idxuong, mavt, tenvt, mota, quycach, mausac, dvt, dacdiem , kho, nhom , create_by, create_date, update_by, update_date, xoa,xacnhan)
  VALUES (@mact, @mact, @tenct, @tenct, @quycach, @mausac, @dvt, @dacdiem, UPPER(@tenkho), @tennhom, @nguoitao, @ngaytao, @nguoisua, @ngaysua, 'N',@xacnhan)
END



